const title = $json.title || '';
const text = `${title} ${$json.summary||''}`.toLowerCase();
const topics = [ ['ai','ml','model','llm','prompt','gpt'], ['security','cyber','vuln','exploit','threat'], ['programming','code','dev','framework','api'], ['product','release','roadmap','feature'], ['research','paper','study','benchmark'] ];
const labels = ['AI','Cybersecurity','Programming','Product','Research'];
let best = 'Misc';
for (let i=0;i<topics.length;i++) { if (topics[i].some(k=>text.includes(k))) { best = labels[i]; break; } }
return [{ ...$json, pivot: best }];

const map = { informational:'Verdant', urgent:'Ember', research:'Abyssal', opinion:'Prismata' };
const intent = ($json.intent || 'informational').toLowerCase();
return [{ ...$json, language: map[intent] || 'Verdant' }];

const crypto = require('crypto');
const payload = `${$json.summary||''}|${$json.url||''}|${$json.pivot||''}|${$json.language||''}`;
return [{ ...$json, hash: crypto.createHash('sha256').update(payload).digest('hex') }];
